import {Injectable} from '@angular/core';
import {HttpClient, HttpParams} from '@angular/common/http';
import {Observable} from 'rxjs';
import {API_NEWS} from '../../../../environments/url';
import {News} from '../dto/news';
import {Pageable} from '../dto/pageable';

@Injectable({
  providedIn: 'root'
})
export class NewsApiService {

  constructor(
    private httpClient: HttpClient
  ) {
  }

  news(offset: number, limit: number): Observable<Pageable<News>> {
    const params = new HttpParams({
      fromObject: {
        offset: offset.toString(),
        limit: limit.toString()
      }
    });
    return this.httpClient.get<Pageable<News>>(API_NEWS, {params});
  }

  newsSingle(id: number): Observable<News> {
    return this.httpClient.get<News>(API_NEWS + id);
  }
}
