import {Component, Input, OnChanges, OnInit, SimpleChanges} from '@angular/core';
import {News} from '../../shared/api/dto/news';
import {CategoriesApiService} from '../../shared/api/categories/categories-api.service';
import {Observable} from 'rxjs';
import {Categories} from '../../shared/api/dto/categories';

@Component({
  selector: 'app-news-item',
  templateUrl: './news-item.component.html',
  styleUrls: ['./news-item.component.sass']
})
export class NewsItemComponent implements OnChanges {
  @Input() size = 'default';
  @Input() news: News;
  categories$: Observable<Categories[]>;
  categoryIdClassName = 'categoryColorBgDefault';

  constructor(
    private categoriesApiService: CategoriesApiService
  ) {
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes.news.currentValue) {
      this.checkCategory();
    }
  }

  checkCategory(): void {
    this.categories$ = this.categoriesApiService.categories();
    this.categories$.subscribe(resp => {
      for (const respKey in resp) {
        if (resp[respKey].name === this.news.group) {
          if (this.news.image === null) {
            this.news.image = resp[respKey].image;
          }
          this.categoryIdClassName = `categoryColorBg${resp[respKey].id}`;
        }
      }
    });
  }

  isSmall(): boolean {
    return this.size === 'small';
  }

  isDefault(): boolean {
    return this.size === 'default';
  }

  isLarge(): boolean {
    return this.size === 'large';
  }
}
